        "heartRate": { "type": "number", "description": "Beats per minute (bpm)" },
        "skinTemperature": { "type": "number", "description": "Degrees Celsius" }
      }
    },
    "noiseExposure": {
      "type": "object",
      "properties": {
        "instantaneous": { "type": "number", "description": "Current dBA" },
        "cumulative": { "type": "number", "description": "Time-weighted average (TWA) against OSHA PEL" }
      }
    },
    "movement": {
      "type": "object",
      "properties": {
        "variability": { "type": "number", "description": "Standard deviation of speed over 5-min window (m/s)" }
      }
    }
  },
  "required": ["workerId", "deviceId", "timestamp", "location"]
}
```

